type GroupishField = {
  readonly _tag: string;
  readonly name: string;
  readonly optional?: boolean;
  readonly fields?: ReadonlyArray<unknown>;
};

/**
 * Collect every field name the definition declares, by group path. An
 * `optional: true` group (the minors-only `parent`, the opt-in `volunteer`) is
 * NOT descended into — it defaults to absent in the form (its inner controls
 * render only when the group is shown), so its NAME alone must be a default key,
 * not each inner field. A non-optional group (`extra`, always rendered for an
 * attendee) IS descended into so each inner control's submit-name is pinned.
 */
const collectNames = (
  fields: ReadonlyArray<GroupishField>,
  prefix = '',
): string[] =>
  fields.flatMap((field) =>
    field._tag === 'nestedGroup' && field.fields && field.optional !== true
      ? collectNames(
          field.fields as ReadonlyArray<GroupishField>,
          `${prefix}${field.name}.`,
        )
      : [`${prefix}${field.name}`],
  );

