323	/**
324	 * The presence requirements a discriminated `variant` imposes on the SELECTED
325	 * branch's fields — at their own paths — collected (not aborted) so a payload
326	 * missing several branch fields surfaces them all at once, exactly as the
327	 * oracle's single accumulating struct filter does
328	 * (`registration-schema.ts:239-302`). A selected branch's leaf that is absent
329	 * emits the leaf's required key at `[name]`; a selected branch's absent
330	 * `nestedGroup` emits a real key at its first inner required field
331	 * ({@link groupPresenceIssue}). An off-variant field is never demanded.
332	 */
333	const variantPresenceIssues = (
334	  variant: FormVariantSet,
335	  value: Record<string, unknown>,
336	): ReadonlyArray<PresenceIssue> => {
337	  const selected = value[variant.discriminator];
338	  const branch = variant.variants.find((v) => v.value === selected);
339	  if (!branch) return [];
340	  const issues: Array<PresenceIssue> = [];
341	  for (const field of branch.fields) {
342	    if (field._tag === 'nestedGroup') {
343	      // An `optional: true` group (registration's minors-only `parent`, the
344	      // opt-in `volunteer`) is legitimately absent — the variant never demands
345	      // it; a PRESENT one still runs its inner checks (the struct codec). A
346	      // non-optional group (the always-rendered `extra`) absent inside the
347	      // selected variant is an error anchored at its first inner required field.
348	      if (field.optional !== true && value[field.name] === undefined) {
349	        const issue = groupPresenceIssue(field);
350	        if (issue) issues.push(issue);
351	      }
352	      continue;
353	    }
354	    if (!isPresenceRequirableLeaf(field)) continue;
355	    if (value[field.name] === undefined) {
356	      issues.push({ path: [field.name], issue: requiredMessageOf(field) });
357	    }
358	  }
359	  return issues;
360	};
